import{_ as t,o,c as a,a3 as n}from"./chunks/framework.CjquFG0V.js";const y=JSON.parse('{"title":"29. Payment Of Wages","description":"","frontmatter":{"title":"29. Payment Of Wages","eba":"Allied Health Professionals 2021-2026","topics":["wages","preliminary","classifications"]},"headers":[],"relativePath":"ebas/allied-health/wages/29-payment-of-wages.md","filePath":"ebas/allied-health/wages/29-payment-of-wages.md"}'),r={name:"ebas/allied-health/wages/29-payment-of-wages.md"};function i(s,e,l,p,m,h){return o(),a("div",null,[...e[0]||(e[0]=[n('<h1 id="_29-payment-of-wages" tabindex="-1">29. Payment Of Wages <a class="header-anchor" href="#_29-payment-of-wages" aria-label="Permalink to &quot;29. Payment Of Wages&quot;">​</a></h1><p><strong>29.1</strong> Frequency of payment</p><p><strong>(a)</strong> The pay period will be weekly or fortnightly.</p><p><strong>(b)</strong> Wages will be paid not later than Thursday following the end of the pay period.</p><p><strong>29.2</strong> Method of payment Wages will be paid by electronic funds transfer into the bank or financial institution account nominated by the Employee, unless otherwise agreed.</p><p><strong>29.3</strong> Employee records</p><p><strong>(a)</strong> Payslip</p><p><strong>(i)</strong> On or prior to pay day, the Employer will provide each Employee with a pay slip.</p><p><strong>(ii)</strong> The payslip will include the information required by the Act and Fair Work Regulations 2009, including but not limited to specifying: A. the period to which the pay slip relates; B. the amount of wages to which the Employee is entitled; C. if an amount was deducted from the gross amount of the payment, the name and number of the fund or account into which the deduction was paid; and D. the net amount for each payment.</p><p><strong>(iii)</strong> To the extent reasonably practicable, payslips will record an Employee’s accrued annual leave, ADOs and personal/carer’s leave or such information will be readily accessible through some other electronic alternative.</p><p><strong>(iv)</strong> Where the Employer introduces a new payroll system, the Employer will where possible ensure that this system provides Employee’s with their accrued annual leave, ADOs and personal/carer’s leave on their payslip</p><p>or be available through some other readily accessible electronic alternative.</p><p><strong>(b)</strong> Records The Employer will comply with its obligations under the Act and Fair Work Regulations 2009 with respect to record keeping, including but not limited to:</p><p><strong>(i)</strong> a requirement to keep a record that sets out any leave the Employee takes and the balance (if any) of the Employee&#39;s entitlement to that leave from time to time;</p><p><strong>(ii)</strong> the inspection and copying of an Employee record by the Employee or former Employee to whom the record relates; and</p><p><strong>(iii)</strong> the requirement to keep accurate Employee records.</p><p><strong>29.4</strong> Deductions Any deductions from an Employee’s pay must be in accordance with section 324 of the Act.</p><p><strong>29.5</strong> Payment on Termination</p><p><strong>(a)</strong> When an Employee’s employment has been terminated by the Employer with notice, payment of all wages and other monies owing to an Employee will be made to the Employee on or before the final day of work of the Employee.</p><p><strong>(b)</strong> Where the Employer terminates the Employee’s employment without notice, payment of all wages and other monies owing to the Employee will made to the Employee within two (2) business days of termination of employment.</p><p><strong>(c)</strong> When an Employee terminates their employment, payment of all wages and other monies owing to an Employee will be made as soon as practicable but not later than the ordinary pay day following the end of employment.</p><p><strong>29.6</strong> Certificate of Service on Termination A certificate of service (or a similar form) including the information at Appendix 6 will be provided to the Employee wherever practicable within 14 days of the date of termination but not greater than 21 days after termination, including where a full or part time Employee terminates employment and becomes a casual Employee.</p>',22)])])}const d=t(r,[["render",i]]);export{y as __pageData,d as default};
